import{_ as t,o as a,c as i,a2 as o}from"./chunks/framework.DGp-bpT-.js";const g=JSON.parse('{"title":"Telegram Integration Setup","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/telegram-setup.md","filePath":"en/guide/telegram-setup.md","lastUpdated":1776149669000}'),s={name:"en/guide/telegram-setup.md"};function r(n,e,l,h,p,d){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="telegram-integration-setup" tabindex="-1">Telegram Integration Setup <a class="header-anchor" href="#telegram-integration-setup" aria-label="Permalink to &quot;Telegram Integration Setup&quot;">​</a></h1><p>Integrating SREBot with Telegram allows the bot to read messages in your group chat, identify alerts from Alertmanager, and automatically reply with detailed RCA reports.</p><hr><h2 id="_1-create-a-bot-via-botfather" tabindex="-1">1. Create a Bot via @BotFather <a class="header-anchor" href="#_1-create-a-bot-via-botfather" aria-label="Permalink to &quot;1. Create a Bot via @BotFather&quot;">​</a></h2><ol><li><p>Open Telegram and search for <a href="https://t.me/BotFather" target="_blank" rel="noreferrer">@BotFather</a>.</p></li><li><p>Send the command <code>/newbot</code>.</p></li><li><p>Choose a <strong>display name</strong> for your bot (e.g. <code>Acme SRE Bot</code>).</p></li><li><p>Choose a <strong>username</strong> ending in <code>bot</code> (e.g. <code>acme_sre_bot</code>).</p></li><li><p>@BotFather will respond with your bot token — it looks like <code>123456789:AAFhd-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</code>.</p><p>Save this token securely; you will need it during configuration.</p></li></ol><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>Single Instance per Token:</strong> Telegram only allows <strong>one</strong> active connection (polling) per bot token.</p><ul><li>If you run two identical bots with the same token, they will &quot;fight&quot; for messages, causing intermittent failures.</li><li>If you need to monitor different clusters/environments separately, <strong>create a unique Telegram bot for each instance</strong> and invite them all to your incident chat.</li></ul></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>The bot&#39;s username will be visible to all chat participants. We recommend using something recognizable to your team, like <code>acme_sre_bot</code>.</p></div><hr><h2 id="_2-configure-bot-permissions-group-privacy" tabindex="-1">2. Configure Bot Permissions (Group Privacy) <a class="header-anchor" href="#_2-configure-bot-permissions-group-privacy" aria-label="Permalink to &quot;2. Configure Bot Permissions (Group Privacy)&quot;">​</a></h2><p>By default, Telegram bots in groups only receive messages that start with <code>/</code> (commands) or mentions of the bot. To allow SREBot to read all messages (including Alertmanager alerts), you must disable Group Privacy mode.</p><ol><li>In the chat with <strong>@BotFather</strong>, send <code>/mybots</code>.</li><li>Select your bot from the list.</li><li>Click <strong>Bot Settings → Group Privacy</strong>.</li><li>Click <strong>Turn off</strong>.</li><li>Verify that the status changed to <code>Group Privacy is DISABLED</code>.</li></ol><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Without this step, the bot <strong>will not see</strong> Alertmanager messages and will never initiate analysis.</p></div><hr><h2 id="_3-retrieve-group-chat-id" tabindex="-1">3. Retrieve Group Chat ID <a class="header-anchor" href="#_3-retrieve-group-chat-id" aria-label="Permalink to &quot;3. Retrieve Group Chat ID&quot;">​</a></h2><p>SREBot needs to know the ID of the specific chat it should monitor. To find it:</p><p><strong>Method 1 — Using @userinfobot:</strong></p><ol><li>Add <a href="https://t.me/userinfobot" target="_blank" rel="noreferrer">@userinfobot</a> to a temporary chat or message it directly.</li><li>Forward any message from your incident chat to it.</li><li>The bot will respond with sender details and a <code>Forwarded from chat</code> entry with the numeric ID.</li></ol><p><strong>Method 2 — Using the Telegram API:</strong></p><ol><li>Add your bot to the desired chat.</li><li>Send any message to the chat.</li><li>Open the following URL in your browser:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.telegram.org/bot&lt;YOUR_TOKEN&gt;/getUpdates</span></span></code></pre></div></li><li>Find the <code>&quot;chat&quot;: {&quot;id&quot;: -100123456789, ...}</code> field in the response.</li></ol><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Group chat IDs are always <strong>negative</strong> and usually start with <code>-100</code>. For example: <code>-1001234567890</code>.</p></div><hr><h2 id="_4-add-the-bot-to-the-chat" tabindex="-1">4. Add the Bot to the Chat <a class="header-anchor" href="#_4-add-the-bot-to-the-chat" aria-label="Permalink to &quot;4. Add the Bot to the Chat&quot;">​</a></h2><ol><li>Open your incident chat in Telegram.</li><li>Click on the chat name → <strong>Add Member</strong>.</li><li>Search for the bot by its username and add it.</li><li>Ensure the bot has permissions to <strong>read messages</strong> — for standard groups, this happens automatically once Group Privacy is disabled (Step 2).</li></ol><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If the chat is a <strong>Supergroup</strong> or a <strong>Channel</strong>, add the bot as an <strong>Administrator</strong> with message-reading privileges. This is required for reading messages posted via the Alertmanager webhook.</p></div><hr><h2 id="_5-configure-the-bot-env" tabindex="-1">5. Configure the Bot (Env) <a class="header-anchor" href="#_5-configure-the-bot-env" aria-label="Permalink to &quot;5. Configure the Bot (Env)&quot;">​</a></h2><p>Once you have gathered all details, add them to your <code>.env</code> file or Helm <code>values.yaml</code> configuration:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Bot token from BotFather</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">TELEGRAM_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">123456789:AAFhd-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Your group chat ID (negative number)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">TELEGRAM_CHANNEL_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">-1001234567890</span></span></code></pre></div><p>Or in <code>values.yaml</code>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">config</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  telegramBotToken</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123456789:AAFhd-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  telegramChatId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-1001234567890&quot;</span></span></code></pre></div><hr><h2 id="how-it-works-post-setup" tabindex="-1">How It Works Post-Setup <a class="header-anchor" href="#how-it-works-post-setup" aria-label="Permalink to &quot;How It Works Post-Setup&quot;">​</a></h2><p>After startup, SREBot connects to Telegram via <strong>long-polling</strong> and monitors the specified chat. When an Alertmanager notification appears, the bot:</p><ol><li>Parses the message to extract alert metadata.</li><li>Checks for deduplication — if the alert is already being processed, it skips it.</li><li>Posts an <strong>Analyzing...</strong> reply placeholder to the original message.</li><li>Executes the AI analysis and replaces the placeholder with the final RCA report.</li></ol>`,34)])])}const u=t(s,[["render",r]]);export{g as __pageData,u as default};
